                      seq: 1,
                      event_type: 'workspace_created',
                      payload_json: '{"ok":true}',
                      created_at: '2026-03-07T00:00:00.000Z',
                    },
                  ],
                } as unknown as T;
              },
            };
          },
        };
      },
