       FROM job_events
       WHERE job_id = ? AND seq > ?
       ORDER BY seq ASC
       LIMIT ?`
    )
    .bind(jobId, fromExclusive, limit)
    .all<JobEventRecord>();

  return result.results.map((row) => {
    let payload: unknown;
    try {
      payload = JSON.parse(row.payload_json);
    } catch {
      payload = { raw: row.payload_json };
    }

    return {
