 */
export async function createCheckpointJob(
  db: D1Database,
  input: CreateCheckpointJobInput
): Promise<JobResponse> {
  const result = await db
    .prepare(
      `INSERT INTO jobs (
         id,
         prompt,
         model,
         status,
         phase,
         source_type,
         checkpoint_id,
         commit_sha,
         source_ref,
         source_project_root,
         build_run_tests_if_present,
